<?php require_once 'config/auth.php'; require_admin(); require_once 'config/db.php'; include 'header.php'; $rows=$pdo->query('SELECT id,name,email,role,created_at FROM users ORDER BY created_at DESC')->fetchAll(PDO::FETCH_ASSOC); ?><h1>Registered Users</h1><table class="table"><tr><th>ID</th><th>Name</th><th>Email</th><th>Role</th><th>Created</th></tr><?php foreach($rows as $u): ?><tr><td><?php echo $u['id']; ?></td><td><?php echo e($u['name']); ?></td><td><?php echo e($u['email']); ?></td><td><span class="badge badge-ai"><?php echo e($u['role']); ?></span></td><td><?php echo e($u['created_at']); ?></td></tr><?php endforeach; ?></table><?php include 'footer.php'; ?>